const html = $json["data"] || $json["body"] || "";
const output = {
  websiteUrl: $json["websiteUrl"] || "",
  companyName: "",
  tagline: "",
  keywords: "",
  ogTitle: "",
  ogDescription: "",
  services: [],
  contactInfo: {},
  socialLinks: [],
  favicon: "",
};

// Extract meta tags
output.companyName = (html.match(/<meta\s+property=["']og:site_name["']\s+content=["'](.*?)["']/i) || [])[1] ||
                     (html.match(/<title>(.*?)<\/title>/i) || [])[1] || "";

output.tagline = (html.match(/<meta\s+name=["']description["']\s+content=["'](.*?)["']/i) || [])[1] || "";
output.ogTitle = (html.match(/<meta\s+property=["']og:title["']\s+content=["'](.*?)["']/i) || [])[1] || "";
output.ogDescription = (html.match(/<meta\s+property=["']og:description["']\s+content=["'](.*?)["']/i) || [])[1] || "";
output.keywords = (html.match(/<meta\s+name=["']keywords["']\s+content=["'](.*?)["']/i) || [])[1] || "";

// Extract schema.org organization JSON-LD
const jsonLdMatch = html.match(/<script[^>]*application\/ld\+json[^>]*>([\s\S]*?)<\/script>/i);
if (jsonLdMatch) {
  try {
    const schemaData = JSON.parse(jsonLdMatch[1]);
    if (schemaData["@type"] === "Organization") {
      output.contactInfo = {
        email: schemaData.email || "",
        phone: schemaData.telephone || "",
        address: schemaData.address?.streetAddress || "",
      };
      output.socialLinks = schemaData.sameAs || [];
      output.companyName ||= schemaData.name;
    }
  } catch (err) {}
}

// Extract social links
const socialMatches = [...html.matchAll(/href=["'](https?:\/\/(www\.)?(facebook|linkedin|instagram|twitter|youtube)\.com[^"']*)["']/gi)];
output.socialLinks = [...new Set([...output.socialLinks, ...socialMatches.map(m => m[1])])];

// Extract favicon
output.favicon = (html.match(/<link[^>]+rel=["']icon["'][^>]+href=["'](.*?)["']/i) || [])[1] || "";

// Extract potential services
const servicesMatch = html.match(/services|solutions|what we do|offerings|capabilities/gi);
if (servicesMatch) {
  output.services = [...new Set(servicesMatch.map(s => s.toLowerCase()))];
}

return [output];

