  'GST': 'Asia/Dubai', 'UAE': 'Asia/Dubai',

  // Australia & Pacific
  'AEST': 'Australia/Sydney', 'AEDT': 'Australia/Sydney', 'AET': 'Australia/Sydney',
  'ACST': 'Australia/Adelaide', 'ACDT': 'Australia/Adelaide',
  'AWST': 'Australia/Perth', 'AWDT': 'Australia/Perth',
  'NZST': 'Pacific/Auckland', 'NZDT': 'Pacific/Auckland', 'NZT': 'Pacific/Auckland',

  // South America
  'BRT': 'America/Sao_Paulo', 'BRST': 'America/Sao_Paulo',
  'ART': 'America/Argentina/Buenos_Aires',
  'CLT': 'America/Santiago',

  // Africa
  'SAST': 'Africa/Johannesburg',

  // UTC
  'UTC': 'UTC', 'GMT': 'UTC', 'Z': 'UTC'
};

// Get timezone from Webhook
let webhookTimezone = null;
try {
  const webhookData = $('Webhook_edit_agent').item.json;

  if (webhookData.body && webhookData.body.timezone) {
    webhookTimezone = webhookData.body.timezone;
  } else if (webhookData.timezone) {
    webhookTimezone = webhookData.timezone;
  }
} catch (error) {
  // Webhook not found, will try input data
}

for (const item of items) {
  const data = item.json;

  // Get timezone with priority: Webhook > Input data > Default
  let inputTimezone = webhookTimezone 
    || data.timezone 
    || (data.body && data.body.timezone)
    || 'UTC';

  inputTimezone = String(inputTimezone).trim();

  let formattedTimezone;

  // If already in IANA format (contains '/'), use as is
  if (inputTimezone.includes('/')) {
    formattedTimezone = inputTimezone;
  } else {
    // Convert abbreviation to IANA format
    const upperInput = inputTimezone.toUpperCase();
    formattedTimezone = timezoneMap[upperInput] || 'UTC';
  }

  // Get business hours from webhook
  let startTime = '09:00';
  let endTime = '17:00';
  let workingDays = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'];

  try {
    const webhookData = $('Webhook_edit_agent').item.json;

    // Try to get from metadata first
    if (webhookData.body && webhookData.body.metadata) {
      if (webhookData.body.metadata.call_availability_start) {
        startTime = webhookData.body.metadata.call_availability_start;
      }
      if (webhookData.body.metadata.call_availability_end) {
        endTime = webhookData.body.metadata.call_availability_end;
      }
      if (webhookData.body.metadata.call_availability_days) {
        workingDays = webhookData.body.metadata.call_availability_days;
      }
    }

    // Try to get from call_availability
    if (webhookData.body && webhookData.body.call_availability) {
      if (webhookData.body.call_availability.start_time) {
        startTime = webhookData.body.call_availability.start_time;
      }
      if (webhookData.body.call_availability.end_time) {
        endTime = webhookData.body.call_availability.end_time;
      }
      if (webhookData.body.call_availability.days) {
        workingDays = webhookData.body.call_availability.days;
      }
    }
  } catch (error) {
    // Use defaults
  }

  // Output formatted data
  output.push({
    json: {
      timezone: formattedTimezone,
      business_hours: `${startTime} - ${endTime}`,
      working_days: workingDays
    }
  });
}

return output;

